# Helper to format a single observation result
def _format_observation(name: str, result: dict) -> str:
    if not result:
        return f"{name}: no result available"
    value = result.get("value")
    unit = result.get("unit") or ""
    ref = result.get("reference_range", {})
    low = ref.get("low")
    high = ref.get("high")
    range_str = ""
    if low is not None and high is not None:
        range_str = f" (ref: {low}‑{high} {unit})"
    elif low is not None:
        range_str = f" (ref low: {low} {unit})"
    elif high is not None:
        range_str = f" (ref high: {high} {unit})"
    value_str = f"{value}" if value is not None else "N/A"
    return f"{name}: {value_str} {unit}{range_str}".strip()

