# ---- Helper to query a resource and collect matching entries ----
def _query_resource(resource_type: str, params: dict) -> list[dict]:
    url = f"{base_url}/{resource_type}"
    results = []
    response = apis.http.get(url=url, params=params)
    bundle = response.json() if hasattr(response, "json") else {}
    while True:
        if "entry" in bundle:
            for entry in bundle["entry"]:
                resource = entry.get("resource", {})
                results.append(resource)
        # pagination
        next_url = None
        if "link" in bundle:
            for link in bundle["link"]:
                if link.get("relation") == "next":
                    next_url = link.get("url")
                    break
        if not next_url:
            break
        response = apis.http.get(url=next_url)
        bundle = response.json() if hasattr(response, "json") else {}
    return results

